local ImageStart_Cache = DrawImage(ImageStart_Data, Vector2.new(160, 180), 1.11864406779661, 1.1015625, 40, 1)
local ImageStart = CreateImageGroup(ImageStart_Cache, Vector2.new(132, 141), Vector2.new(160, 180))
ImageStart.Visible = true

local ImageSmash_Cache = DrawImage(ImageSmash_Data, Vector2.new(160, 180), 1.11864406779661, 1.1015625, 40, 1)
local ImageSmash = CreateImageGroup(ImageSmash_Cache, Vector2.new(132, 141), Vector2.new(160, 180))
ImageSmash.Visible = false

local lastMouse1 = false

while true do
    wait(0.01)
    if isrbxactive() then
        local mouse1 = ismouse1pressed()
        local mPos = Vector2.new(Mouse.X, Mouse.Y)

        if mouse1 and not lastMouse1 then
            if SmashBtn.Visible and mPos.X >= SmashBtn.Position.X and mPos.X <= SmashBtn.Position.X + SmashBtn.Size.X and
               mPos.Y >= SmashBtn.Position.Y and mPos.Y <= SmashBtn.Position.Y + SmashBtn.Size.Y then
                
                isSmashed = not isSmashed

                if isSmashed then
                    SmashBtn.Color = Theme.ButtonOn
                    SmashBtn_Border.Color = Color3.fromRGB(255, 255, 255)
                    SmashBtn_Text.Text = "SMASHED !!!"
                    
                    ImageStart.Visible = false
                    ImageSmash.Visible = true
                    
                    MainMenu_Border.Color = Theme.AccentNeon
                else
                    SmashBtn.Color = Theme.ButtonOff
                    SmashBtn_Border.Color = Theme.AccentNeon
                    SmashBtn_Text.Text = "SMASH ???"
                    
                    ImageStart.Visible = true
                    ImageSmash.Visible = false
                    
                    MainMenu_Border.Color = Theme.Border
                end
            end
        end

        lastMouse1 = mouse1
    end
end